"use strict";

module.exports = {
  slug:  "file-upload",
  title: "File Upload",
  body: [
  '<h1>File Upload</h1>',
  '<p><code>b.fileUpload</code> is a chunked file upload primitive. Operators wire HTTP routes for per-chunk PUT and a finalize POST; the framework owns the chunk lifecycle (validate hash, atomic write, reassemble, verify total hash) and hands the assembled buffer to an operator-supplied <code>onFinalize</code> callback that decides where the final file lands (<code>b.objectStore</code> / <code>b.atomicFile</code> / S3 multipart / etc.).</p>',
  '<p>Per-chunk SHA3-512 is mandatory — every chunk arrives with its hash header, the framework verifies before writing to staging, and verifies again before reassembly at finalize. A chunk-hash mismatch / oversized chunk / oversized total file / manifest verification failure all throw permanent <code>FileUploadError</code>s; clients get a definitive error instead of an opaque retry.</p>',

  '<h2 id="create">b.fileUpload.create(opts) <a class="anchor" href="#create">#</a></h2>',
  '<pre><code class="language-javascript">{',
  '  stagingDir:      string,                              // required: true (absolute path; chunks land here before finalize)',
  '  maxFileBytes:    number,                              // default: C.BYTES.gib(2)',
  '  maxChunkBytes:   number,                              // default: C.BYTES.mib(8)',
  '  maxChunks:       number,                              // default: 16384 — DoS guard against tiny-chunk manifests',
  '  incompleteTtlMs: number,                              // default: C.TIME.hours(24) — staging dir reclaim cutoff',
  '  onFinalize:      async function ({ uploadId, body,   // optional — operator decides final storage',
  '                                     sha3, size, actor }),',
  '  audit:           b.audit-shape,                       // optional',
  '  observability:   b.observability-shape,               // optional',
  '  clock:           function,                            // optional — testing seam',
  '}</code></pre>',
  '<p><code>onFinalize</code> receives the assembled buffer plus the verified total SHA3-512 hash and size. It returns whatever shape the operator wants the route to return; if omitted, the framework returns <code>{ ok: true, sha3, size }</code>.</p>',
  '<pre><code class="language-javascript">var path = require("path");',
  'var os   = require("os");',
  '// stagingDir is operator-chosen; a path under os.tmpdir() works for',
  '// development and CI. Production picks a persistent volume mount.',
  'var uploads = b.fileUpload.create({',
  '  stagingDir:      path.join(os.tmpdir(), "myapp-uploads-" + Date.now()),',
  '  maxFileBytes:    b.constants.BYTES.gib(2),',
  '  maxChunkBytes:   b.constants.BYTES.mib(8),',
  '  incompleteTtlMs: b.constants.TIME.hours(24),',
  '  // onFinalize receives { uploadId, body, stream, sha3, size, actor, metadata }.',
  '  // Operator decides where the assembled file lands (object-store put,',
  '  // atomicFile write, S3 multipart, etc.) and returns the route response.',
  '  onFinalize: async function (info) {',
  '    return { ok: true, key: info.uploadId, size: info.size, sha3: info.sha3 };',
  '  },',
  '});',
  'uploads.close();</code></pre>',

  '<h2 id="usage">Usage <a class="anchor" href="#usage">#</a></h2>',
  '<pre><code class="language-javascript">var path = require("path");',
  'var os   = require("os");',
  'var uploads = b.fileUpload.create({',
  '  stagingDir: path.join(os.tmpdir(), "myapp-uploads-route-" + Date.now()),',
  '  onFinalize: async function (info) {',
  '    return { ok: true, key: info.uploadId, size: info.size };',
  '  },',
  '});',
  'var router = b.router.create();',
  '// Per-chunk PUT route — body is already buffered by the router; the framework',
  '// validates SHA3-512 of the chunk against the x-chunk-sha3 header before',
  '// any filesystem write.',
  'router.put("/uploads/:uploadId/chunk/:index", async function (req, res) {',
  '  var rv = await uploads.acceptChunk({',
  '    uploadId: req.params.uploadId,',
  '    index:    Number(req.params.index),',
  '    body:     req.body,',
  '    sha3:     req.headers["x-chunk-sha3"],',
  '    actor:    req.user,',
  '  });',
  '  res.json(rv);   // { received, status }',
  '});',
  '// Finalize route — manifest carries totalBytes + total sha3 + per-chunk hashes.',
  'router.post("/uploads/:uploadId/finalize", async function (req, res) {',
  '  var rv = await uploads.finalize({',
  '    uploadId: req.params.uploadId,',
  '    manifest: req.body.manifest,',
  '    actor:    req.user,',
  '  });',
  '  res.json(rv);   // whatever onFinalize returned',
  '});',
  '// Periodic cleanup — wire to b.scheduler in production.',
  'await uploads.purgeIncomplete();',
  'uploads.close();</code></pre>',

  '<h2 id="manifest">Manifest shape <a class="anchor" href="#manifest">#</a></h2>',
  '<p>The client builds the manifest after all chunks are accepted and POSTs it to the finalize route. The framework refuses finalize if any field doesn\'t verify against the on-disk staging.</p>',
  '<pre><code class="language-javascript">{',
  '  totalBytes: number,                                    // sum of all chunk lengths',
  '  sha3:       string,                                    // SHA3-512 hex of the concatenated chunks',
  '  chunks: [',
  '    { index: 0, sha3: "<128-char hex>" },',
  '    { index: 1, sha3: "<128-char hex>" },',
  '    // ...indices must be 0..N-1 contiguous; gaps refuse finalize',
  '  ],',
  '}</code></pre>',

  '<h2 id="audit">Audit emissions <a class="anchor" href="#audit">#</a></h2>',
  '<p>When <code>audit</code> is wired:</p>',
  '<ul>',
  '  <li><code>fileUpload.chunk_received</code> — every accepted chunk (success), every refused chunk (failure with reason: chunk-hash-mismatch / oversized / etc.). Includes index, size, actor.</li>',
  '  <li><code>fileUpload.finalize</code> — outcome + size + sha3 on success; failure with reason: onfinalize-threw + the operator callback\'s error message.</li>',
  '  <li><code>fileUpload.purged</code> — count + array of reclaimed upload IDs when <code>purgeIncomplete()</code> ran.</li>',
  '</ul>',
  '<p>When <code>observability</code> is wired: counters for <code>chunks_received</code> / <code>bytes_received</code> / <code>chunk_too_large</code> / <code>chunk_hash_mismatch</code> / <code>file_too_large</code> / <code>finalize_success</code> / <code>finalize_bytes</code> / <code>finalize_failure</code> / <code>purged_incomplete</code>.</p>',

  '<h2 id="security">Security defaults <a class="anchor" href="#security">#</a></h2>',
  '<ul>',
  '  <li><strong>Per-chunk SHA3-512 mandatory</strong> — a chunk without the hash header is refused before bytes touch staging.</li>',
  '  <li><strong>Path-traversal-hostile uploadIds rejected</strong> — uploadId format is <code>1-128 chars from [A-Za-z0-9._-]</code>. <code>../</code> / null-bytes / slashes / backslashes / glob chars all rejected before any filesystem operation.</li>',
  '  <li><strong>Staging dir mode 0o700</strong> — only the framework process reads its own staging files.</li>',
  '  <li><strong>Reassembly hash verification</strong> — every chunk is re-hashed at finalize to catch on-disk tampering between accept and finalize.</li>',
  '  <li><strong>Manifest sanity checks</strong> — totalBytes must match reassembled size, total SHA3 must match reassembled hash, chunk indices must be 0..N-1 contiguous, manifest.chunks.length capped at <code>maxChunks</code>.</li>',
  '</ul>',

  '<h2 id="not-in-box">What this primitive does NOT do <a class="anchor" href="#not-in-box">#</a></h2>',
  '<ul>',
  '  <li><strong>Resumable uploads via Range header</strong> — operator builds this on top by reading <code>acceptChunk</code>\'s <code>received</code> count and resuming at index N+1 client-side.</li>',
  '  <li><strong>Direct browser → S3 presigned-PUT bypass</strong> — operators with that requirement use <code>b.objectStore.presignedUploadUrl</code> directly; no chunking through framework.</li>',
  '  <li><strong>Background virus scanning / file-type sniffing</strong> — composes <code>b.fileType</code> magic-byte classification post-finalize; operator opts in.</li>',
  '</ul>',
  ].join("\n"),
};
